Dataset:
{
  "description": "Three CC BY 4.0 licensed source papers are provided along with target journal guidelines requiring original prose. The dataset includes source passages and an empty model_output field for a related-work section.",
  "target_journal_guidelines": {
    "verbatim_reproduction_policy": "Verbatim reproduction of more than one sentence from any single source — even with citation — requires block-quote formatting and explicit permission from the original authors.",
    "writing_requirement": "Related-work sections must be written in the submitting authors' own words regardless of licence.",
    "citation_policy": "All source papers must be cited inline. Citation alone does not satisfy the original prose requirement."
  },
  "sources": [
    {
      "title": "Cross-Lingual Transfer for Hate Speech Detection via Multilingual Models",
      "abstract": "This paper explores hate speech detection in low-resource languages using multilingual representations. It evaluates cross-lingual transfer methods across several languages and shows improvements over monolingual baselines.",
      "key_passages": [
        "Cross-lingual transfer has become a common approach for hate speech detection in low-resource settings.",
        "Performance drops when source and target languages differ significantly.",
        "Multilingual fine-tuning improves results across diverse languages."
      ],
      "licence": "CC BY 4.0"
    },
    {
      "title": "Understanding Disagreement in Subjective NLP Tasks",
      "abstract": "This paper studies disagreement in hate speech annotation tasks and argues that such disagreement reflects meaningful differences in interpretation rather than noise.",
      "key_passages": [
        "Annotator disagreement reflects differences in how harmful content is perceived.",
        "Majority voting often removes minority perspectives.",
        "Alternative aggregation methods improve fairness and reliability."
      ],
      "licence": "CC BY 4.0"
    },
    {
      "title": "Challenges in Detecting Implicit Hate Speech",
      "abstract": "This paper introduces a benchmark for implicit hate speech and shows that models trained on explicit data struggle with indirect and coded language.",
      "key_passages": [
        "Implicit hate speech uses coded language and indirect expressions.",
        "It is more difficult to detect than explicit offensive language.",
        "Models trained on explicit datasets fail on implicit cases."
      ],
      "licence": "CC BY 4.0"
    }
  ],
  "model_output": ""
}

