    },
    {
      "line_id": 7,
      "protected": false,
      "description": "Available for additional analyses",
      "code": "# [AVAILABLE FOR MODIFICATION]"
    },
    {
      "line_id": 8,
      "protected": false,
      "description": "Available for additional analyses",
      "code": "# [AVAILABLE FOR MODIFICATION]"
    }
  ],
  "available_data": {
