    "n_negative": 68,
    "data_source": "Electronic health records, single-centre retrospective cohort, 2021-2023",
    "recommended_validation": "5-fold stratified cross-validation given small N (n_train=76, n_test=19 on 80/20 split)",
    "missing_data": "Complete cases only after exclusions \u2014 no imputation required",
    "epv": {
      "value": 3.0,
      "formula": "EPV = n_positive_outcomes / n_predictors = 27 / 9",
      "n_positive": 27,
      "n_predictors": 9,
      "reference_threshold": ">=10 recommended (Peduzzi et al. 1996, J Clin Epidemiol); >=5 minimum",
      "interpretation": "EPV of 3.0 is below recommended thresholds, supporting use of a parsimonious regularised model."
    }
  },
  "features": [
    {
      "name": "Age",
