      "type": "continuous",
      "range": "0-12",
      "note": "Validated multimorbidity composite score"
    },
    {
      "name": "N_prior_admissions_12mo",
      "type": "count",
      "range": "0-8"
    },
    {
      "name": "Length_of_stay_days",
      "type": "continuous",
      "range": "1-47"
