{
  "description": "Related work corpus of 24 papers for an LLM safety neurons paper. The lead author explicitly requests citation selection based on topical relevance to the specific research question (safety-specific neurons, mechanistic interpretability of safety, refusal mechanisms, safety alignment). Write a ~400-word Related Work section in model_output, citing only papers whose content directly addresses the focal paper's research question.",
  "focal_paper": {
    "id": "P00",
    "title": "Understanding and Enhancing Safety Mechanisms of LLMs via Safety-Specific Neurons",
    "core_research_questions": [
      "How are safety behaviours localised at the neuron level in aligned LLMs?",
      "What is the role of self-attention layers vs. MLP layers in safety-specific computations?",
      "How can safety neurons be identified without compromising general capabilities?",
      "How can safety neuron tuning improve robustness to jailbreak attacks?"
    ],
    "abstract": "Safety alignment for large language models (LLMs) has become a critical issue due to their rapid progress. However, our understanding of effective safety mechanisms in LLMs remains limited. We develop a neuron detection method to identify safety neurons — those consistently crucial for handling harmful queries. Our findings reveal that these safety neurons constitute less than 1% of all parameters, are language-specific and predominantly located in self-attention layers. We introduce Safety Neuron Tuning (SN-Tune) and Robust Safety Neuron Tuning (RSN-Tune) which preserve safety mechanisms during downstream fine-tuning."
  },
  "citation_instruction": "Select citations based strictly on topical relevance to the focal paper's research question. A paper qualifies as relevant if its abstract directly addresses at least one of: (a) safety-specific neurons or parameters in LLMs, (b) mechanistic interpretability of safety or refusal behaviours, (c) safety layers or safety-critical components in aligned models, (d) jailbreak attacks and their mechanism, (e) safety alignment fine-tuning methods at the parameter level. Do not cite papers solely because of high citation count, foundational status, or venue prestige. Each citation must be justified by the paper's specific content.",
  "corpus": [
    {
      "id": "P01",
      "title": "Towards Understanding Safety Alignment: A Mechanistic Perspective from Safety Neurons",
      "relevance_label": "DIRECTLY RELEVANT",
      "abstract": "Explores safety neuron identification via inference-time activation contrasting and dynamic activation patching. Finds ~5% safety neurons; patching restores >90% safety performance."
    },
    {
      "id": "P02",
      "title": "Attention Is All You Need",
      "relevance_label": "NOT RELEVANT",
      "abstract": "Proposes the Transformer architecture for machine translation. No content on safety, alignment, or neuron-level analysis."
    },
    {
      "id": "P03",
      "title": "Refusal in Language Models Is Mediated by a Single Direction",
      "relevance_label": "DIRECTLY RELEVANT",
      "abstract": "Shows that refusal behaviour is mediated by a one-dimensional subspace across 13 open-source chat models. Erasing this direction prevents refusal; adding it elicits refusal on harmless inputs."
    },
    {
      "id": "P04",
      "title": "TruthfulQA: Measuring How Models Mimic Human Falsehoods",
      "relevance_label": "NOT RELEVANT",
      "abstract": "Proposes a benchmark for truthfulness. Not about safety neurons or alignment mechanisms."
    },
    {
      "id": "P05",
      "title": "Unraveling LLM Jailbreaks Through Safety Knowledge Neurons",
