        "note": "[TO COMPLETE — evaluate the 20-second threshold against documented fraud cases and recommend whether this parameter creates dual-use risk]"
      },
      "output": "Synthesised speech preserving speaker voice identity; TTS interface",
      "deployment_platform": "Mobile application (iOS and Android) with backend inference",
      "processing": "On-device inference preferred; encrypted cloud fallback for low-resource devices"
    },
