    "deployment_constraints": "[TO COMPLETE — specify access controls, authentication, and consent verification mechanisms]",
    "data_governance": {
      "voice_data_storage": "Encrypted on-device storage (AES-256); cloud backup optional with explicit informed consent",
      "retention_policy": "Voice profile retained until user deletion request; deletion within 30 days of request",
      "third_party_sharing": "None without explicit informed consent"
    },
    "target_users": {
      "primary": "ALS patients referred by neurologist or speech-language pathologist",
      "access_model": "[TO COMPLETE — specify whether prescription-based or open-access, and why]"
    }
  },
  "background_materials_summary": {
    "source_1": {
      "title": "Arup Internal Report on Deepfake Fraud Incident (2024)",
      "verified": true,
      "key_finding": "A USD 25.6 million corporate fraud was executed using deepfake voice and video clones of company executives. The voice cloning system required fewer than 30 seconds of target speaker audio for enrolment, sourced from publicly available recordings.",
      "relevance_to_voicesync": "VoiceSync requires 20 seconds of enrolment audio — below the threshold used in this documented fraud case. The 20-second enrolment audio, if accessible to a malicious actor, could enable identity fraud."
    },
    "source_2": {
      "title": "FBI Cyber Division Voice Cloning Fraud Report (2024)",
      "verified": true,
      "key_finding": "Voice cloning fraud complaints to IC3 increased 300% from 2022 to 2023. Total reported losses exceeded USD 180 million in 2023. Typical attack vector: spoofed executive voices in wire transfer authorisation calls.",
      "relevance_to_voicesync": "Rapid growth in voice cloning fraud at the time VoiceSync is being designed."
    },
    "source_3": {
      "title": "Privacy International Voice Cloning Tool Audit (2024)",
      "verified": true,
      "key_finding": "All 14 consumer voice cloning tools tested produced human-indistinguishable synthetic speech from 30-second audio clips sourced from YouTube. Waveform analysis failed to reliably distinguish real from synthetic in blind listening tests.",
      "relevance_to_voicesync": "The technical threshold for effective voice cloning (30 seconds) is close to VoiceSync's planned enrolment duration (20 seconds). Consumer-grade tools are already sufficient for fraudulent use."
    }
  },
  "ethical_framework": {
    "beneficence": "Restoring speech capability for ALS patients is a clear clinical need. The population is well-defined and the benefit is direct.",
    "non_maleficence": "The documented risk of voice cloning fraud is substantial and the technical threshold (20-30 seconds) is already sufficient for effective fraud. A 20-second enrolment system creates meaningful dual-use potential.",
    "design_principle": "Both the beneficial use case and the dual-use risk must be addressed in the design. The clinical need justifies proceeding; it does not justify proceeding without mitigation."
  }
}

